SELECT COUNT(*) 
FROM heritage_sites 
WHERE town = 'Queenstown';

SELECT place_name, place_address, town, postcode, thr_status, public_access
FROM heritage_sites
WHERE site_id = 1;

SELECT site_id, place_name
FROM heritage_sites
WHERE year_built >= (SELECT AVG(year_built) FROM heritage_sites);

SELECT place_name, place_address
FROM heritage_sites
WHERE year_built = (
    SELECT MAX(year_built)
    FROM heritage_sites
);

SELECT *
FROM status_history
WHERE status_change_date > '2022-01-01';

SELECT COUNT(attachment_id) as user_1_attachments
FROM attachments
WHERE uploaded_by = 1;
